  1	import * as React from 'react';
  2	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  3	import { CommonModalProps } from '@odf/shared/modals';
  4	import { S3Commands } from '@odf/shared/s3';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import { TFunction, Trans } from 'react-i18next';
  7	import {
  8	  Modal,
  9	  ModalVariant,
 10	  Button,
 11	  ButtonVariant,
 12	  TextInput,
 13	  TextInputTypes,
 14	  FormGroup,
 15	} from '@patternfly/react-core';
 16	
 17	const DELETE = 'delete';
 18	
 19	type DeleteBucketPolicyModalProps = {
 20	  bucketName: string;
 21	  s3Client: S3Commands;
 22	  triggerRefresh: () => void;
 23	};
 24	
 25	const getTextInputLabel = (t: TFunction) => (
 26	  <Trans t={t as any}>
 27	    <b>
 28	      confirm this action, type <i>{{ delete: DELETE }}</i> in the text input
 29	      field.
 30	    </b>
 31	  </Trans>
 32	);
 33	
 34	const DeleteBucketPolicyModal: React.FC<
 35	  CommonModalProps<DeleteBucketPolicyModalProps>
 36	> = ({
 37	  closeModal,
 38	  isOpen,
 39	  extraProps: { bucketName, s3Client, triggerRefresh },
 40	}) => {
 41	  const { t } = useCustomTranslation();
 42	
 43	  const [deleteText, setDeleteText] = React.useState<string>('');
 44	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 45	  const [error, setError] = React.useState<Error>();
 46	
 47	  const onDelete = async (event) => {
 48	    event.preventDefault();
 49	    setInProgress(true);
 50	
 51	    try {
 52	      await s3Client.deleteBucketPolicy({ Bucket: bucketName });
 53	
 54	      setInProgress(false);
 55	      closeModal();
 56	      triggerRefresh();
 57	    } catch (err) {
 58	      setInProgress(false);
 59	      setError(err);
 60	    }
 61	  };
 62	
 63	  return (
 64	    <Modal
 65	      title={t('Confirm delete bucket policy?')}
 66	      titleIconVariant="warning"
 67	      isOpen={isOpen}
 68	      onClose={closeModal}
 69	      description={
 70	        <div className="text-muted">
 71	          {t(
 72	            'This action will remove all associated access permissions, and any users or applications relying on this policy may lose access. This change cannot be undone.'
 73	          )}
 74	        </div>
 75	      }
 76	      variant={ModalVariant.medium}
 77	      actions={[
 78	        <ButtonBar
 79	          inProgress={inProgress}
 80	          errorMessage={error?.message || JSON.stringify(error)}
 81	        >
 82	          <span>
 83	            <Button
 84	              variant={ButtonVariant.danger}
 85	              onClick={onDelete}
 86	              isDisabled={deleteText !== DELETE || !!error}
 87	              className="pf-v6-u-mr-xs"
 88	            >
 89	              {t('Confirm delete')}
 90	            </Button>
 91	            <Button
 92	              variant={ButtonVariant.link}
 93	              onClick={closeModal}
 94	              className="pf-v6-u-ml-xs"
 95	            >
 96	              {t('Cancel')}
 97	            </Button>
 98	          </span>
 99	        </ButtonBar>,
100	      ]}
101	    >
102	      <FormGroup
103	        label={getTextInputLabel(t)}
104	        fieldId="delete-objects"
105	        className="pf-v6-u-mt-lg pf-v6-u-mb-sm"
106	      >
107	        <TextInput
108	          value={deleteText}
109	          id="delete-policy"
110	          onChange={(_event, value) => setDeleteText(value)}
111	          type={TextInputTypes.text}
112	          placeholder={DELETE}
113	        />
114	      </FormGroup>
115	    </Modal>
116	  );
117	};
118	
119	export default DeleteBucketPolicyModal;

